40	export function decodeFloat32Vector(value: unknown, dimension?: number): number[] {
41	  if (!value) return [];
42	  const bytes = Buffer.isBuffer(value)
43	    ? value
44	    : value instanceof Uint8Array
45	      ? Buffer.from(value)
46	      : Array.isArray(value)
47	        ? Buffer.from(value)
48	        : null;
49	  if (!bytes || bytes.length % 4 !== 0) return [];
50	  const count = dimension && dimension > 0 ? Math.min(dimension, bytes.length / 4) : bytes.length / 4;
51	  const out: number[] = [];
52	  for (let i = 0; i < count; i++) {
53	    out.push(bytes.readFloatLE(i * 4));
54	  }
