  if (!bounds) {
    return (
      <div
        role="status"
        style={{
          padding: "1rem",
          color: "var(--parchment-dim)",
          fontSize: "0.85rem",
        }}
      >
        No embedded conclusions to plot.
      </div>
    );
  }

  const containerStyle: CSSProperties = {
    position: "relative",
    width: "100%",
    background: "var(--stone-light)",
    border: "1px solid var(--border)",
    borderRadius: 2,
  };

  return (
    <div style={containerStyle}>
      <svg
        ref={svgRef}
        viewBox={`0 0 ${width} ${height}`}
        width="100%"
        role="application"
        aria-label="Embedding explorer canvas"
        style={{ display: "block", touchAction: "none", cursor: lassoPath ? "crosshair" : "default" }}
        onPointerDown={onPointerDown}
        onPointerMove={onPointerMove}
        onPointerUp={onPointerUp}
        onPointerCancel={onPointerUp}
      >
        {/* Edges first so points sit on top */}
        {overlayEdges.map((e) => {
          const a = renderedById.get(e.a);
          const b = renderedById.get(e.b);
          if (!a || !b) return null;
          const stroke = e.kind === "contradicts" ? "#a14b3a" : "#5d8a4a";
          const opacity = 0.25 + 0.55 * Math.min(1, Math.max(0, e.score));
          return (
            <line
              key={`${e.kind}:${e.a}:${e.b}`}
              x1={a.px}
              y1={a.py}
              x2={b.px}
              y2={b.py}
              stroke={stroke}
              strokeWidth={1.1}
              strokeDasharray={e.kind === "contradicts" ? "4 3" : undefined}
              opacity={opacity}
              pointerEvents="none"
            />
          );
        })}

        {/* LOD: density mosaic. Hidden when selection is small enough
            to render fully. */}
        {useLOD &&
          hexBins.map((bin, i) => {
            const intensity = Math.min(1, bin.n / maxBinCount);
            return (
              <rect
                key={`bin-${i}`}
                x={bin.cx - HEX_SIZE / 2}
                y={bin.cy - HEX_SIZE / 2}
                width={HEX_SIZE - 1}
                height={HEX_SIZE - 1}
                fill="#c9944a"
                opacity={0.10 + intensity * 0.35}
                pointerEvents="none"
              />
            );
          })}

        {/* Full-fidelity points */}
        {fullPoints.map((n) => {
          const isSelected = selection.has(n.id);
          const isFocused = focusedId === n.id;
          const baseColor = tierColor(n.data.confidenceTier);
          const r = isFocused ? 8 : isSelected ? 6 : useLOD ? 4 : 5;
          const opacity = isFocused || isSelected ? 1 : 0.78;
          return (
            <circle
              key={n.id}
              data-role="point"
              data-id={n.id}
              cx={n.px}
              cy={n.py}
              r={r}
              fill={baseColor}
              stroke={isFocused ? "var(--parchment)" : isSelected ? "#f1d77a" : "none"}
              strokeWidth={isFocused ? 1.5 : isSelected ? 1.2 : 0}
              opacity={opacity}
              style={{ cursor: "pointer" }}
              onMouseEnter={(e) => {
                setHovered(n);
                setTooltipPos({ x: e.clientX, y: e.clientY });
              }}
              onMouseMove={(e) => setTooltipPos({ x: e.clientX, y: e.clientY })}
              onMouseLeave={() => setHovered(null)}
              onClick={(evt) => {
                evt.stopPropagation();
                onPointClick(n.id);
              }}
            />
          );
        })}

        {lassoPath && lassoPath.length > 1 && (
          <path
            d={lassoD}
            fill="rgba(212,160,23,0.10)"
            stroke="#d4a017"
            strokeWidth={1}
            strokeDasharray="4 3"
            pointerEvents="none"
          />
        )}
      </svg>

      {hovered && (
        <div
          style={{
            position: "fixed",
            left: tooltipPos.x + 12,
            top: tooltipPos.y - 8,
            background: "var(--stone)",
            border: "1px solid var(--border)",
            borderRadius: 2,
            padding: "0.5rem 0.75rem",
            maxWidth: "320px",
            fontSize: "0.78rem",
            color: "var(--parchment)",
            zIndex: 100,
            pointerEvents: "none",
            boxShadow: "0 2px 8px rgba(0,0,0,0.3)",
          }}
        >
          <div
            className="mono"
            style={{
              fontSize: "0.6rem",
              color: "var(--amber-dim)",
              textTransform: "uppercase",
              marginBottom: "0.25rem",
            }}
          >
            {hovered.data.confidenceTier} · {hovered.data.topicHint || "general"}
          </div>
          <p style={{ margin: 0, lineHeight: 1.4 }}>
            {hovered.data.text.slice(0, 220)}
            {hovered.data.text.length > 220 ? "…" : ""}
          </p>
          {hovered.data.methods.length > 0 && (
            <p
              className="mono"
              style={{
                margin: "0.4rem 0 0",
                color: "var(--parchment-dim)",
                fontSize: "0.65rem",
              }}
            >
              methods: {hovered.data.methods.join(", ")}
            </p>
          )}
        </div>
      )}
    </div>
  );
}

