  const [tooltipPos, setTooltipPos] = useState({ x: 0, y: 0 });
  const [viewport, setViewport] = useState<{ cx: number; cy: number; scale: number }>({
    cx: 0.5,
    cy: 0.5,
    scale: 1,
  });

