            <p
              className="mono"
              style={{
                marginTop: "0.6rem",
                fontSize: "0.7rem",
                color: "var(--parchment-dim)",
              }}
            >
              methods: {focusedPoint.methods.join(", ")}
            </p>
          )}
          <div style={{ display: "flex", gap: "0.5rem", marginTop: "0.9rem", flexWrap: "wrap" }}>
            <button
              type="button"
              onClick={() => onShowNeighborhood(focusedPoint.id)}
              style={smallButtonStyle}
            >
